sns_client = boto3.client('sns')

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    """
    Lambda function to publish messages to SNS topics.
    
    Expected event structure:
    {
        "topic_arn": "arn:aws:sns:region:account-id:topic-name",
        "message": "Message content",
        "subject": "Optional subject",
        "notification_type": "email|sms|push|default",
        "message_attributes": {
            "key": "value"
        },
        "batch_messages": [
            {
                "topic_arn": "arn:aws:sns:...",
                "message": "Message 1"
            }
        ]
    }
    """
    try:
        if 'batch_messages' in event and event['batch_messages']:
            return handle_batch_publish(event['batch_messages'])
        
        topic_arn = event.get('topic_arn')
        message = event.get('message')
        subject = event.get('subject', '')
        notification_type = event.get('notification_type', 'default')
        message_attributes = event.get('message_attributes', {})
        
        if not topic_arn:
            return create_error_response('topic_arn is required', 400)
        
        if not message:
            return create_error_response('message is required', 400)
        
        result = publish_message(
            topic_arn=topic_arn,
            message=message,
            subject=subject,
            notification_type=notification_type,
            message_attributes=message_attributes
        )
        
        return create_success_response(result)
        
    except Exception as e:
        return create_error_response(str(e), 500)


def publish_message(
    topic_arn: str,
    message: str,
    subject: str = '',
    notification_type: str = 'default',
    message_attributes: Optional[Dict[str, Any]] = None
) -> Dict[str, Any]:
    """
    Publish a message to an SNS topic based on notification type.
    """
    if notification_type == 'email':
        return publish_email_notification(topic_arn, message, subject, message_attributes)
    elif notification_type == 'sms':
        return publish_sms_notification(topic_arn, message, message_attributes)
    elif notification_type == 'push':
        return publish_push_notification(topic_arn, message, message_attributes)
    elif notification_type == 'structured':
        return publish_structured_notification(topic_arn, message, subject, message_attributes)
    else:
        return publish_default_notification(topic_arn, message, subject, message_attributes)


