def publish_sms_notification(
    topic_arn: str,
    message: str,
    message_attributes: Optional[Dict[str, Any]] = None
) -> Dict[str, Any]:
    """
    Publish an SMS notification (limited to 160 characters).
    """
    sms_message = message[:160] if len(message) > 160 else message
    
    params = {
        'TopicArn': topic_arn,
        'Message': sms_message
    }
    
    attrs = {
        'AWS.SNS.SMS.SMSType': {
            'DataType': 'String',
            'StringValue': 'Transactional'
        },
        'notification_type': {
            'DataType': 'String',
            'StringValue': 'sms'
        }
    }
    
    if message_attributes:
        attrs.update(format_message_attributes(message_attributes))
    
    params['MessageAttributes'] = attrs
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'notification_type': 'sms',
        'topic_arn': topic_arn,
        'message_length': len(sms_message),
        'timestamp': datetime.utcnow().isoformat()
    }


