def handle_batch_publish(batch_messages: List[Dict[str, Any]]) -> Dict[str, Any]:
    """
    Handle batch publishing of multiple messages.
    """
    results = []
    errors = []
    
    for idx, msg_data in enumerate(batch_messages):
        try:
            topic_arn = msg_data.get('topic_arn')
            message = msg_data.get('message')
            subject = msg_data.get('subject', '')
            notification_type = msg_data.get('notification_type', 'default')
            message_attributes = msg_data.get('message_attributes', {})
            
            if not topic_arn or not message:
                errors.append({
                    'index': idx,
                    'error': 'Missing topic_arn or message'
                })
                continue
            
            result = publish_message(
                topic_arn=topic_arn,
                message=message,
                subject=subject,
                notification_type=notification_type,
                message_attributes=message_attributes
            )
            
            results.append({
                'index': idx,
                'result': result
            })
            
        except Exception as e:
            errors.append({
                'index': idx,
                'error': str(e)
            })
    
    return {
        'statusCode': 200 if not errors else 207,
        'body': json.dumps({
            'success': True,
            'total_messages': len(batch_messages),
            'successful': len(results),
            'failed': len(errors),
            'results': results,
            'errors': errors,
            'timestamp': datetime.utcnow().isoformat()
        })
    }


def format_message_attributes(attributes: Dict[str, Any]) -> Dict[str, Dict[str, str]]:
    """
    Format message attributes for SNS.
    """
    formatted_attrs = {}
    
    for key, value in attributes.items():
        if isinstance(value, dict) and 'DataType' in value:
            formatted_attrs[key] = value
        elif isinstance(value, (int, float)):
            formatted_attrs[key] = {
                'DataType': 'Number',
                'StringValue': str(value)
            }
        elif isinstance(value, str):
            formatted_attrs[key] = {
                'DataType': 'String',
                'StringValue': value
            }
        elif isinstance(value, list):
            formatted_attrs[key] = {
                'DataType': 'String.Array',
                'StringValue': json.dumps(value)
            }
        else:
            formatted_attrs[key] = {
                'DataType': 'String',
                'StringValue': str(value)
            }
    
    return formatted_attrs


def format_email_message(message: str) -> str:
    """
    Format message for email delivery.
    """
    timestamp = datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S UTC')
    
    formatted_message = f"""
{message}

---
Sent: {timestamp}
Event Notification System
"""
    return formatted_message.strip()


def create_push_message(message_data: Dict[str, Any]) -> Dict[str, str]:
    """
    Create platform-specific push notification messages.
    """
    default_message = message_data.get('default', 'New notification')
    
    push_message = {
        'default': default_message
    }
    
    if 'title' in message_data and 'body' in message_data:
        gcm_data = {
            'notification': {
                'title': message_data['title'],
                'body': message_data['body']
            }
        }
        if 'data' in message_data:
            gcm_data['data'] = message_data['data']
        
        push_message['GCM'] = json.dumps(gcm_data)
        
        apns_data = {
            'aps': {
                'alert': {
                    'title': message_data['title'],
                    'body': message_data['body']
                },
                'sound': 'default'
            }
        }
        if 'data' in message_data:
            apns_data.update(message_data['data'])
        
        push_message['APNS'] = json.dumps(apns_data)
        push_message['APNS_SANDBOX'] = json.dumps(apns_data)
    
    return push_message


def create_structured_message(message_data: Dict[str, Any], subject: str = '') -> Dict[str, str]:
    """
    Create structured message for different protocols.
    """
    default_message = message_data.get('default', json.dumps(message_data))
    
    structured_message = {
        'default': default_message
    }
    
    if 'email' in message_data:
        structured_message['email'] = message_data['email']
    elif subject:
        structured_message['email'] = f"{subject}\n\n{default_message}"
    
    if 'sms' in message_data:
        structured_message['sms'] = message_data['sms'][:160]
    else:
        structured_message['sms'] = default_message[:160]
    
    if 'http' in message_data:
        structured_message['http'] = message_data['http']
    
    if 'https' in message_data:
        structured_message['https'] = message_data['https']
    
    if 'sqs' in message_data:
        structured_message['sqs'] = message_data['sqs']
    
    return structured_message


def create_success_response(data: Dict[str, Any]) -> Dict[str, Any]:
    """
    Create a success response.
    """
    return {
        'statusCode': 200,
        'body': json.dumps({
            'success': True,
            'data': data,
            'timestamp': datetime.utcnow().isoformat()
        })
    }


def create_error_response(error_message: str, status_code: int = 500) -> Dict[str, Any]:
    """
    Create an error response.
    """
    return {
        'statusCode': status_code,
        'body': json.dumps({
            'success': False,
            'error': error_message,
            'timestamp': datetime.utcnow().isoformat()
        })
    }